import React, { useState, useEffect } from 'react';
import Select from 'react-select';

import './AddPurchase.css';

const AddPurchase = ({ handleAdd, locations, vendors }) => {
  const initialPurchaseState = {
    location: '',
    materialid: '',
    quantity: '',
    price: '',
    vendor: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);

  useEffect(() => {
    const fetchMaterialChanges = async () => {
      if (newPurchase.materialid) {
        try {
          const response = await fetch(`http://localhost:8081/materialchangesAPI/${newPurchase.materialid}`);
          const data = await response.json();
          console.log('Data fetched:', data);

          if (data && data.price && data.vendor) {
            // Find the vendor with the given ID in the vendors array
            const selectedVendor = vendors.find((vendor) => vendor.id === data.vendor);
            if (selectedVendor) {
              // If the vendor is found, update newPurchase state with price and vendor name
              setNewPurchase((prevPurchase) => ({
                ...prevPurchase,
                price: data.price,
                vendor: selectedVendor.name, // Set the selected vendor name instead of ID
              }));
            } else {
              // If the vendor is not found in vendors array, reset vendor to empty string
              setNewPurchase((prevPurchase) => ({
                ...prevPurchase,
                price: data.price,
                vendor: '', // Reset the vendor value to empty string
              }));
            }
          } else {
            // If no data available for the selected materialid, update the price and reset vendor to empty string
            setNewPurchase((prevPurchase) => ({
              ...prevPurchase,
              price: '',
              vendor: '', // Reset the vendor value to empty string
            }));
          }
        } catch (error) {
          console.error('Error fetching material changes:', error);
        }
      } else {
        // Clear the default values if no materialid is selected
        setNewPurchase((prevPurchase) => ({
          ...prevPurchase,
          price: '',
          vendor: '', // Reset the vendor value to empty string
        }));
      }
    };

    fetchMaterialChanges();
  }, [newPurchase.materialid, vendors]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase({
      ...newPurchase,
      [name]: value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Convert the selected vendor name back to vendor ID before submitting to the API
    const selectedVendor = vendors.find((vendor) => vendor.name === newPurchase.vendor);
    if (selectedVendor) {
      setNewPurchase((prevPurchase) => ({
        ...prevPurchase,
        vendor: selectedVendor.id,
      }));
    }
    handleAdd(newPurchase);
    setNewPurchase(initialPurchaseState);
  };

  const vendorOptions = vendors.map((vendor) => ({
    value: vendor.name, // Use vendor name as the value for dropdown options
    label: vendor.name,
  }));

  const handleVendorChange = (selectedOption) => {
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendor: selectedOption ? selectedOption.value : '', // Set the selected vendor name in the state
    }));
  };

  return (
    <form onSubmit={handleSubmit} className='add-purchase-form'>
      <div>
        <label>Location:</label>
        <select name="location" value={newPurchase.location} onChange={handleChange}>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={newPurchase.materialid} onChange={handleChange} />
      </div>
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={newPurchase.quantity} onChange={handleChange} />
      </div>
      <div>
        <label>Price:</label>
        <input
          type="text"
          name="price"
          value={newPurchase.price}
          onChange={handleChange}
        />
      </div>
      <div>
        <label>Vendor:</label>
        <Select
          options={vendorOptions}
          value={vendorOptions.find((option) => option.value === newPurchase.vendor)} // Find the vendor option based on the selected vendor name
          onChange={handleVendorChange}
          placeholder="Select a Vendor"
          isSearchable // Enable search functionality
        />
      </div>
      <button type="submit" className="add_purchase_btn">Add Purchase</button>
    </form>
  );
};

export default AddPurchase;
